 34→export function createSketchObject(name = 'Untitled Object', overrides = {}) {
 35→  const now = new Date().toISOString();
 36→  return {
 37→    id: overrides.id || generateId('obj'),
 38→    name,
 39→    description: overrides.description || '',
 40→    summary: overrides.summary || '',
 41→    category: overrides.category || 'general',
 42→    templateType: overrides.templateType || null,
 43→    templateParams: overrides.templateParams ? { ...overrides.templateParams } : null,
 44→    dimensions: overrides.dimensions ? { ...overrides.dimensions } : {},
 45→    origin: clonePoint(overrides.origin),
 46→    source: overrides.source || 'custom',
 47→    editingPolicy: overrides.editingPolicy || 'manual',
 48→    assemblyIds: [...(overrides.assemblyIds || [])],
 49→    partIds: [...(overrides.partIds || [])],
 50→    defaultName: overrides.defaultName || name,
 51→    createdAt: overrides.createdAt || now,
 52→    updatedAt: overrides.updatedAt || now,
 53→  };
