 56→export function buildObjectTree(project, object) {
 57→  if (!object) return null;
 58→
 59→  const assemblies = (project.assemblies || [])
 60→    .filter((assembly) => assembly.objectId === object.id);
 61→  const assemblyById = new Map(assemblies.map((assembly) => [assembly.id, assembly]));
 62→  const partsByAssemblyId = new Map();
 63→
 64→  for (const part of project.parts || []) {
 65→    if (!part.assemblyId || part.objectId !== object.id) continue;
 66→    const list = partsByAssemblyId.get(part.assemblyId) || [];
 67→    list.push(part);
 68→    partsByAssemblyId.set(part.assemblyId, list);
 69→  }
 70→
 71→  function buildAssemblyNode(assembly) {
 72→    const childAssemblies = assemblies
 73→      .filter((candidate) => candidate.parentAssemblyId === assembly.id)
 74→      .sort((a, b) => (a.sortIndex || 0) - (b.sortIndex || 0));
 75→    const partNodes = (partsByAssemblyId.get(assembly.id) || [])
 76→      .sort((a, b) => (a.sortIndex || 0) - (b.sortIndex || 0))
 77→      .map((part) => ({
 78→        kind: 'part',
 79→        id: part.id,
 80→        partId: part.id,
 81→        role: part.role || part.generatedRole || part.type,
 82→        name: part.name,
 83→      }));
 84→
 85→    return {
 86→      kind: 'assembly',
 87→      id: assembly.id,
 88→      assemblyId: assembly.id,
 89→      name: assembly.name,
 90→      role: assembly.role || 'assembly',
 91→      description: assembly.description || '',
 92→      children: [
 93→        ...childAssemblies.map(buildAssemblyNode),
 94→        ...partNodes,
 95→      ],
 96→    };
 97→  }
 98→
 99→  const rootAssemblies = assemblies
100→    .filter((assembly) => !assembly.parentAssemblyId || !assemblyById.has(assembly.parentAssemblyId))
101→    .sort((a, b) => (a.sortIndex || 0) - (b.sortIndex || 0));
102→  const rootPartNodes = (project.parts || [])
103→    .filter((part) => part.objectId === object.id && !part.assemblyId)
104→    .sort((a, b) => (a.sortIndex || 0) - (b.sortIndex || 0))
105→    .map((part) => ({
106→      kind: 'part',
107→      id: part.id,
108→      partId: part.id,
109→      role: part.role || part.generatedRole || part.type,
110→      name: part.name,
111→    }));
112→
113→  return {
114→    kind: 'object',
115→    id: object.id,
116→    objectId: object.id,
117→    name: object.name,
118→    role: object.templateType || object.category || 'object',
119→    children: [
120→      ...rootAssemblies.map(buildAssemblyNode),
121→      ...rootPartNodes,
122→    ],
123→  };
124→}
