 206→function detachManagedObject(project, objectId) {
 207→  return {
 208→    ...project,
 209→    objects: (project.objects || []).map((object) => (
 210→      object.id === objectId
 211→        ? {
 212→            ...object,
 213→            source: 'custom',
 214→            editingPolicy: 'manual',
 215→            templateType: null,
 216→            templateParams: null,
 217→            summary: object.summary || 'Detached custom object',
 218→            updatedAt: new Date().toISOString(),
 219→          }
 220→        : object
 221→    )),
 222→    assemblies: project.assemblies.map((assembly) => (
 223→      assembly.objectId === objectId
 224→        ? {
 225→            ...assembly,
 226→            source: 'manual',
 227→            role: assembly.role || null,
 228→          }
 229→        : assembly
 230→    )),
 231→    parts: project.parts.map((part) => (
 232→      part.objectId === objectId
 233→        ? {
 234→          ...part,
 235→            source: 'manual',
 236→            locked: false,
 237→          }
 238→        : part
 239→    )),
 240→  };
 241→}
 242→
 243→function addGeneratedObject(project, generated) {
 244→  return {
 245→    ...project,
 246→    objects: [...(project.objects || []), generated.object],
 247→    assemblies: [...project.assemblies, ...generated.assemblies],
 248→    parts: [...project.parts, ...generated.parts.map(sanitizePart)],
 249→  };
 250→}
 251→
 252→function collectConstraintsForObject(project, objectId) {
 253→  const objectPartIds = new Set(
 254→    project.parts.filter((part) => part.objectId === objectId).map((part) => part.id)
 255→  );
 256→  return (project.constraints || []).filter((constraint) => {
 257→    if (constraint.type === 'equal_spacing') {
 258→      return (constraint.partIds || []).some((id) => objectPartIds.has(id));
 259→    }
 260→    return objectPartIds.has(constraint.sourcePartId) || objectPartIds.has(constraint.targetPartId);
 261→  });
 262→}
 263→
 264→function buildRoleMap(parts, objectId) {
 265→  const map = new Map();
 266→  for (const part of parts) {
 267→    if (part.objectId === objectId && part.generatedRole) {
 268→      map.set(part.id, part.generatedRole);
 269→    }
 270→  }
 271→  return map;
 272→}
 273→
 274→function buildReverseRoleMap(parts, objectId) {
 275→  const map = new Map();
 276→  for (const part of parts) {
 277→    if (part.objectId === objectId && part.generatedRole) {
 278→      map.set(part.generatedRole, part.id);
 279→    }
 280→  }
 281→  return map;
 282→}
 283→
 284→function remapConstraints(constraints, oldRoleMap, newRoleMap) {
 285→  return constraints
 286→    .map((constraint) => {
 287→      if (constraint.type === 'equal_spacing') {
 288→        const newPartIds = (constraint.partIds || []).map((id) => {
 289→          const role = oldRoleMap.get(id);
 290→          return role ? (newRoleMap.get(role) || null) : id;
 291→        }).filter(Boolean);
 292→
 293→        let newRefId = constraint.referencePartId;
 294→        if (newRefId) {
 295→          const refRole = oldRoleMap.get(newRefId);
 296→          newRefId = refRole ? (newRoleMap.get(refRole) || null) : newRefId;
 297→        }
 298→
 299→        if (newPartIds.length < 2) return null;
 300→        return { ...constraint, partIds: newPartIds, referencePartId: newRefId };
 301→      }
 302→
 303→      let newSourceId = constraint.sourcePartId;
 304→      let newTargetId = constraint.targetPartId;
 305→
 306→      const sourceRole = oldRoleMap.get(newSourceId);
 307→      if (sourceRole) newSourceId = newRoleMap.get(sourceRole) || null;
 308→
 309→      const targetRole = oldRoleMap.get(newTargetId);
 310→      if (targetRole) newTargetId = newRoleMap.get(targetRole) || null;
 311→
 312→      if (!newSourceId || !newTargetId) return null;
 313→      return { ...constraint, sourcePartId: newSourceId, targetPartId: newTargetId };
 314→    })
 315→    .filter(Boolean);
 316→}
 317→
 318→function rebuildManagedObject(project, object, params) {
 319→  const oldAssemblyIds = project.assemblies
 320→    .filter((assembly) => assembly.objectId === object.id)
 321→    .map((assembly) => assembly.id);
 322→
 323→  // Collect constraints referencing old parts and build role map before stripping
 324→  const affectedConstraints = collectConstraintsForObject(project, object.id);
 325→  const oldRoleMap = buildRoleMap(project.parts, object.id);
 326→
 327→  const strippedProject = removeObjectArtifacts(project, object.id);
 328→  const generated = generateObjectFromTemplate(object.templateType, params, {
 329→    objectId: object.id,
 330→    name: object.name,
 331→    origin: object.origin,
 332→  });
 333→
 334→  const nextProject = addGeneratedObject({
 335→    ...strippedProject,
 336→    objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
 337→    sheets: retargetManagedViewports(strippedProject.sheets, object.id, oldAssemblyIds),
 338→  }, generated);
 339→
 340→  // Remap constraints to new part IDs via role matching
 341→  if (affectedConstraints.length > 0) {
 342→    const newRoleMap = buildReverseRoleMap(nextProject.parts, object.id);
 343→    const remapped = remapConstraints(affectedConstraints, oldRoleMap, newRoleMap);
 344→    // Merge: keep constraints not affected + add remapped ones
 345→    const affectedIds = new Set(affectedConstraints.map((c) => c.id));
 346→    const kept = (nextProject.constraints || []).filter((c) => !affectedIds.has(c.id));
 347→    return { ...nextProject, constraints: [...kept, ...remapped] };
 348→  }
 349→
 350→  return nextProject;
 351→}
 352→
 353→function sketchReducer(state, action) {
 354→  switch (action.type) {
 355→    case 'SKETCH_NEW': {
 356→      const newProject = action.project || createSketchProject();
 357→      return {
 358→        project: newProject,
 359→        isDirty: false,
 360→        savedSnapshot: snapshotSketch(newProject),
 361→        history: [],
 362→        future: [],
 363→      };
 364→    }
 365→
 366→    case 'SKETCH_LOAD': {
 367→      const loaded = normalizeSketchObjects(action.project);
 368→      return {
 369→        project: loaded,
 370→        isDirty: false,
 371→        savedSnapshot: snapshotSketch(loaded),
 372→        history: [],
 373→        future: [],
 374→      };
 375→    }
 376→
 377→    case 'PART_ADD': {
 378→      const part = sanitizePart(action.part);
 379→      const assembly = part.assemblyId
 380→        ? state.project.assemblies.find((entry) => entry.id === part.assemblyId)
 381→        : null;
 382→      const nextPart = assembly && assembly.objectId
 383→        ? { ...part, objectId: assembly.objectId }
 384→        : part;
 385→      let nextProject = {
 386→        ...state.project,
 387→        updatedAt: new Date().toISOString(),
 388→        parts: [...state.project.parts, nextPart],
 389→      };
 390→      nextProject = applyConstraints(nextProject);
 391→      return applyUpdate(state, nextProject);
 392→    }
 393→
 394→    case 'PART_UPDATE': {
 395→      const managedObject = getManagedObjectForPart(state.project, action.part.id);
 396→      if (managedObject && !action.allowManagedUpdate) return state;
 397→
 398→      let nextProject = {
 399→        ...state.project,
 400→        updatedAt: new Date().toISOString(),
 401→        parts: state.project.parts.map((part) => {
 402→          if (part.id !== action.part.id) return part;
 403→          const merged = mergePart(part, action.part);
 404→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
 405→        }),
 406→      };
 407→      nextProject = applyConstraints(nextProject);
 408→      nextProject = updateBoundDimensions(nextProject, action.part.id);
 409→      return applyUpdate(state, nextProject);
 410→    }
 411→
 412→    case 'PART_DELETE': {
 413→      const managedObject = getManagedObjectForPart(state.project, action.partId);
