 857→          sheet.id === action.sheetId
 858→            ? {
 859→                ...sheet,
 860→                viewports: (sheet.viewports || []).map((viewport) => (
 861→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
 862→                )),
 863→              }
 864→            : sheet
 865→        )),
 866→      });
 867→
 868→    case 'SKETCH_SHEET_VIEWPORT_DELETE':
 869→      return applyUpdate(state, {
 870→        ...state.project,
 871→        updatedAt: new Date().toISOString(),
 872→        sheets: (state.project.sheets || []).map((sheet) => (
 873→          sheet.id === action.sheetId
 874→            ? { ...sheet, viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId) }
 875→            : sheet
 876→        )),
 877→      });
 878→
 879→    case 'TEMPLATE_GENERATE': {
 880→      const generated = generateObjectFromTemplate(action.templateType, action.params, {
 881→        objectId: action.objectId,
 882→        name: action.name,
 883→        origin: action.origin,
 884→      });
 885→      return applyUpdate(state, {
 886→        ...addGeneratedObject(state.project, generated),
 887→        updatedAt: new Date().toISOString(),
 888→      });
 889→    }
 890→
 891→    case 'TEMPLATE_REGENERATE': {
 892→      const object = action.objectId
 893→        ? getManagedObject(state.project, action.objectId)
 894→        : getManagedObjectForAssembly(state.project, action.assemblyId);
 895→      if (!object || !object.templateType) return state;
 896→
 897→      const nextProject = rebuildManagedObject(state.project, object, action.params);
 898→      return applyUpdate(state, {
 899→        ...nextProject,
 900→        updatedAt: new Date().toISOString(),
 901→      });
 902→    }
 903→
 904→    case 'TEMPLATE_DETACH': {
 905→      const object = action.objectId
 906→        ? getManagedObject(state.project, action.objectId)
 907→        : getManagedObjectForAssembly(state.project, action.assemblyId);
 908→      if (!object) return state;
 909→      return sketchReducer(state, { type: 'OBJECT_DETACH', objectId: object.id });
 910→    }
 911→
 912→    case 'UNDO': {
 913→      if (state.history.length === 0) return state;
 914→      const previous = state.history[state.history.length - 1];
 915→      return {
 916→        ...state,
 917→        project: previous,
 918→        history: state.history.slice(0, -1),
 919→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
 920→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
 921→      };
 922→    }
 923→
 924→    case 'REDO': {
 925→      if (state.future.length === 0) return state;
 926→      const next = state.future[0];
 927→      return {
 928→        ...state,
 929→        project: next,
 930→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
 931→        future: state.future.slice(1),
 932→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
 933→      };
 934→    }
 935→
 936→    case 'MARK_SAVED':
 937→      return {
 938→        ...state,
 939→        isDirty: false,
 940→        savedSnapshot: snapshotSketch(state.project),
 941→      };
 942→
 943→    default:
 944→      return state;
 945→  }
 946→}
 947→
 948→function createInitialState(project) {
 949→  return {
 950→    project,
 951→    isDirty: false,
 952→    savedSnapshot: snapshotSketch(project),
 953→    history: [],
 954→    future: [],
 955→  };
 956→}
 957→
 958→export function SketchProvider({ children, initialProject }) {
 959→  const [state, dispatch] = useReducer(
 960→    sketchReducer,
 961→    normalizeSketchObjects(initialProject || createSketchProject()),
 962→    createInitialState
 963→  );
 964→
 965→  return (
 966→    <SketchContext.Provider value={{ state, dispatch }}>
 967→      {children}
 968→    </SketchContext.Provider>
 969→  );
 970→}
 971→
 972→export function useSketch() {
 973→  const ctx = useContext(SketchContext);
 974→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
 975→  const { state, dispatch } = ctx;
 976→
 977→  const getPart = useCallback(
 978→    (partId) => state.project.parts.find((part) => part.id === partId) || null,
 979→    [state.project.parts]
 980→  );
 981→
 982→  const getAssembly = useCallback(
 983→    (assemblyId) => state.project.assemblies.find((assembly) => assembly.id === assemblyId) || null,
 984→    [state.project.assemblies]
 985→  );
 986→
 987→  const getObject = useCallback(
 988→    (objectId) => (state.project.objects || []).find((object) => object.id === objectId) || null,
 989→    [state.project.objects]
 990→  );
 991→
 992→  const getPartsForAssembly = useCallback(
 993→    (assemblyId) => state.project.parts.filter((part) => part.assemblyId === assemblyId),
 994→    [state.project.parts]
 995→  );
 996→
 997→  const getChildParts = useCallback(
 998→    (parentId) => state.project.parts.filter((part) => part.parentId === parentId),
 999→    [state.project.parts]
1000→  );
1001→
1002→  const getAssembliesForObject = useCallback(
1003→    (objectId) => state.project.assemblies.filter((assembly) => assembly.objectId === objectId),
1004→    [state.project.assemblies]
1005→  );
1006→
1007→  return {
1008→    project: state.project,
1009→    isDirty: state.isDirty,
1010→    canUndo: state.history.length > 0,
1011→    canRedo: state.future.length > 0,
1012→    dispatch,
1013→    getPart,
1014→    getAssembly,
1015→    getObject,
1016→    getPartsForAssembly,
1017→    getChildParts,
1018→    getAssembliesForObject,
1019→  };
1020→}
